<?php
namespace Tests\Feature;use App\Domain\Loot\Data\LootDrop;use App\Domain\Loot\LootGenerator;use App\Domain\Random\RandomNumberGenerator;use App\Models\Monster;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class LootSequenceRandom implements RandomNumberGenerator{public $values;public $calls=0;public function __construct(array $v){$this->values=$v;}public function randomInt(int $min,int $max):int{$this->calls++;return array_shift($this->values);}}
class LootGeneratorTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);}public function test_none_one_multiple_and_variable_drops(){$wolf=Monster::where('code','grey_wolf')->first();$none=(new LootGenerator(new LootSequenceRandom([7001,2501])))->generateFor($wolf);$this->assertCount(0,$none->drops());$one=(new LootGenerator(new LootSequenceRandom([7000,2,2501])))->generateFor($wolf);$this->assertCount(1,$one->drops());$this->assertSame(2,$one->drops()[0]->quantity());$many=(new LootGenerator(new LootSequenceRandom([1,3,1])))->generateFor($wolf);$this->assertCount(2,$many->drops());$this->assertContainsOnlyInstancesOf(LootDrop::class,$many->drops());}public function test_fixed_quantity_does_not_consume_extra_roll(){$wolf=Monster::where('code','grey_wolf')->first();$rng=new LootSequenceRandom([7001,2500]);$r=(new LootGenerator($rng))->generateFor($wolf);$this->assertSame(2,$rng->calls);$this->assertSame('wolf_fang',$r->drops()[0]->itemCode());}public function test_inactive_monster_and_hidden_item_are_excluded(){$wolf=Monster::where('code','grey_wolf')->first();$wolf->status='inactive';$wolf->save();$this->expectException(\InvalidArgumentException::class);(new LootGenerator(new LootSequenceRandom([])))->generateFor($wolf);}}
